CREATE TYPE "import_status" AS ENUM ('PENDING','PROCESSING','PREVIEW_READY','VALIDATED','PARTIALLY_IMPORTED','FAILED','REPROCESSED');
CREATE TABLE "import_jobs" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"status" import_status NOT NULL DEFAULT 'PENDING',"connector_id" text,"mapping_version" text,"requested_by" uuid REFERENCES "users"("id"),"summary" jsonb NOT NULL DEFAULT '{}');
CREATE INDEX "import_jobs_tenant_status_idx" ON "import_jobs"("tenant_id","status");
CREATE TABLE "import_files" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"import_job_id" uuid NOT NULL REFERENCES "import_jobs"("id"),"storage_key" text NOT NULL,"original_name_encrypted" text NOT NULL,"mime_type" text NOT NULL,"byte_size" numeric(20,0) NOT NULL,"sha256" text NOT NULL,"importer_version" text NOT NULL);
CREATE UNIQUE INDEX "import_files_tenant_hash_uq" ON "import_files"("tenant_id","sha256");
CREATE TABLE "import_rows" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"import_file_id" uuid NOT NULL REFERENCES "import_files"("id"),"row_number" numeric(12,0) NOT NULL,"status" text NOT NULL,"raw_encrypted" text NOT NULL,"normalized" jsonb NOT NULL DEFAULT '{}',"business_key" text);
CREATE INDEX "import_rows_file_idx" ON "import_rows"("import_file_id");
CREATE TABLE "import_errors" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"import_job_id" uuid NOT NULL REFERENCES "import_jobs"("id"),"import_row_id" uuid REFERENCES "import_rows"("id"),"code" text NOT NULL,"severity" text NOT NULL,"message" text NOT NULL,"blocking" boolean NOT NULL DEFAULT false);
CREATE TABLE "evidence_documents" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"import_file_id" uuid NOT NULL REFERENCES "import_files"("id"),"source_channel" text NOT NULL,"document_type" text NOT NULL,"storage_key" text NOT NULL,"sha256" text NOT NULL,"immutable" boolean NOT NULL DEFAULT true,"captured_at" timestamptz NOT NULL DEFAULT now());
CREATE INDEX "evidence_tenant_hash_idx" ON "evidence_documents"("tenant_id","sha256");
